Deep-clone handling Dates, Maps, Sets, RegExps, and circular references requires a recursive traversal with a Map to track seen objects:

```js
function deepClone(value, seen = new Map()) {
  if (value === null || typeof value !== 'object') return value;
  if (seen.has(value)) return seen.get(value); // circular: return same clone ref
  if (value instanceof Date) return new Date(value.getTime());
  if (value instanceof RegExp) return new RegExp(value.source, value.flags);
  if (value instanceof Map) {
    const m = new Map();
    seen.set(value, m);
    value.forEach((v, k) => m.set(deepClone(k, seen), deepClone(v, seen)));
    return m;
  }
  if (value instanceof Set) {
    const s = new Set();
    seen.set(value, s);
    value.forEach(v => s.add(deepClone(v, seen)));
    return s;
  }
  const clone = Array.isArray(value) ? [] : Object.create(Object.getPrototypeOf(value));
  seen.set(value, clone);
  for (const key of Reflect.ownKeys(value)) {
    clone[key] = deepClone(value[key], seen);
  }
  return clone;
}
```
Using `Map` (not `WeakMap`) as the seen registry is necessary here because we need to return the cloned reference for cycles, and WeakMap cannot return values in the same lookup path.

810.answer:
Recursive equality at depth 100,000 will cause a stack overflow. Use an iterative approach with an explicit stack of pairs to compare:

```js
function deepEqual(a, b) {
  const stack = [[a, b]];
  const seen = new Map(); // handle circular refs
  while (stack.length) {
    let [x, y] = stack.pop();
    if (x === y) continue;
    if (x === null || y === null || typeof x !== 'object' || typeof y !== 'object') return false;
    // circular reference guard
    if (seen.get(x) === y) continue;
    seen.set(x, y);
    const xKeys = Object.keys(x), yKeys = Object.keys(y);
    if (xKeys.length !== yKeys.length) return false;
    for (const k of xKeys) {
      if (!Object.prototype.hasOwnProperty.call(y, k)) return false;
      stack.push([x[k], y[k]]);
    }
  }
  return true;
}
```
The iterative approach uses the heap instead of the call stack, so depth 100,000 is safe. The `seen` map prevents infinite loops for circular structures. Note: key order does not matter since we check both key counts and individual membership.

