Flatten with special handling for empty objects `{}`, empty arrays `[]`, and keys containing dots:

```js
function flatten(obj, prefix = '', result = {}) {
  if (obj === null || typeof obj !== 'object') {
    result[prefix] = obj;
    return result;
  }
  const keys = Object.keys(obj);
  if (keys.length === 0) {
    // empty object or array: preserve as leaf
    result[prefix] = Array.isArray(obj) ? [] : {};
    return result;
  }
