    const escapedKey = key.replace(/\./g, '\\.');
    const newKey = prefix ? `${prefix}.${escapedKey}` : escapedKey;
    flatten(obj[key], newKey, result);
  }
  return result;
}
// flatten({a: {b: {}}, c: []}) -> {'a.b': {}, 'c': []}
// flatten({'a.b': 1}) -> {'a\\.b': 1}  (dot escaped)
```
