Unflatten with conflict detection: a path conflict occurs when one key implies a value at a node that another key treats as an intermediate object (e.g., 'a' as a leaf and 'a.b' as a path through it):

```js
function unflatten(flat) {
  const result = {};
  for (const [path, val] of Object.entries(flat)) {
    // Split on unescaped dots
    const parts = path.split(/(?<!\\)\./).map(p => p.replace(/\\\./g, '.'));
    let cur = result;
    for (let i = 0; i < parts.length - 1; i++) {
      const p = parts[i];
      if (p in cur) {
        if (typeof cur[p] !== 'object' || cur[p] === null) {
          throw new Error(`Conflict: '${parts.slice(0,i+1).join('.')}' is both a leaf and an intermediate node`);
        }
      } else {
        cur[p] = {};
      }
      cur = cur[p];
    }
    const last = parts[parts.length - 1];
    if (last in cur && typeof cur[last] === 'object' && cur[last] !== null && !Array.isArray(cur[last])) {
      throw new Error(`Conflict: '${path}' would overwrite an intermediate node`);
    }
    cur[last] = val;
  }
  return result;
}
```
The lookbehind `(?<!\\)\.` splits on unescaped dots only, handling keys that contain literal dots.

