Recursive config merge where arrays are replaced (not merged) and null/undefined override:

```js
function mergeConfig(base, override) {
  if (override === null || override === undefined) return override; // explicit null wins
  if (Array.isArray(override)) return [...override]; // arrays replaced, not merged
  if (typeof override !== 'object') return override; // primitive wins
  if (typeof base !== 'object' || base === null || Array.isArray(base)) return { ...override };
  const result = { ...base };
  for (const [key, val] of Object.entries(override)) {
    if (Object.prototype.hasOwnProperty.call(base, key)) {
      result[key] = mergeConfig(base[key], val);
    } else {
      result[key] = val;
    }
  }
  return result;
}
// mergeConfig({a:[1,2],b:{c:1}}, {a:[3],b:{d:2}})
// -> {a:[3], b:{c:1,d:2}}
// Arrays replaced: [1,2] -> [3]
// Objects merged: {c:1} + {d:2} -> {c:1,d:2}
```
The key design decision: arrays are always replaced by the override value, never concatenated. Undefined in override means 'do not change'; null means 'set to null'.

