Topological sort with self-loops, disconnected components, and cycle detection using Kahn's algorithm:

```python
from collections import defaultdict, deque

def topological_sort(nodes: list, edges: list[tuple]) -> list:
    """Returns sorted list or raises ValueError on cycle (including self-loops)."""
    in_degree = {n: 0 for n in nodes}
    adj = defaultdict(list)
    for u, v in edges:
        if u == v:
            raise ValueError(f'Self-loop detected at node {u!r}')
        adj[u].append(v)
        in_degree[v] += 1
        if v not in in_degree:
            in_degree[v] = 0  # ensure all nodes present

    queue = deque(n for n in nodes if in_degree[n] == 0)
    result = []
    while queue:
        node = queue.popleft()
        result.append(node)
        for neighbor in adj[node]:
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    if len(result) != len(nodes):
        cycle_nodes = [n for n in nodes if in_degree[n] > 0]
        raise ValueError(f'Cycle detected involving nodes: {cycle_nodes}')
    return result

# Disconnected nodes with in_degree 0 are added to queue at initialization
# so disconnected components are naturally handled
```

