JSON diff function reporting changes at precise paths, handling additions, deletions, type changes, and array reordering:

```python
def json_diff(old, new, path='') -> list[dict]:
    diffs = []
    if type(old) != type(new):
        diffs.append({'path': path or '/', 'type': 'type_change',
                      'old': old, 'new': new})
        return diffs
    if isinstance(old, dict):
        all_keys = set(old) | set(new)
        for k in sorted(all_keys):
            child_path = f'{path}.{k}' if path else k
            if k not in old:
                diffs.append({'path': child_path, 'type': 'added', 'value': new[k]})
            elif k not in new:
                diffs.append({'path': child_path, 'type': 'removed', 'value': old[k]})
            else:
                diffs.extend(json_diff(old[k], new[k], child_path))
    elif isinstance(old, list):
        # Report by index; length change is also captured
        for i in range(max(len(old), len(new))):
            child_path = f'{path}[{i}]'
            if i >= len(old):
                diffs.append({'path': child_path, 'type': 'added', 'value': new[i]})
            elif i >= len(new):
                diffs.append({'path': child_path, 'type': 'removed', 'value': old[i]})
            else:
                diffs.extend(json_diff(old[i], new[i], child_path))
    else:
        if old != new:
            diffs.append({'path': path or '/', 'type': 'changed', 'old': old, 'new': new})
    return diffs
```

